// Prepare items for SplitInBatches - one item per business
const businesses = $input.all().map(item => item.json);
const today = new Date().toISOString().split('T')[0];

return businesses.map(biz => ({
  json: {
    ...biz,
    today: today
  }
}));

// =========================================================
// Budget Circuit Breaker - Part XI Operating Bible Logic
// Pure data logic, no LLM needed
// =========================================================

const budgetEntry = $('Fetch Today Budget Entry').first().json;
const metricsRaw = $('Fetch 7-Day Metrics').all().map(i => i.json);
const biz = $('Loop Each Business').first().json;

const today = biz.today;
const businessId = biz.business_id;
const businessName = biz.name;
const status = biz.status; // seed, traction, scale, breakout
const currentMrr = parseFloat(biz.current_mrr) || 0;

// ---- Budget Tier Limits (Part XI) ----
const tierLimits = {
  seed: 20,
  traction: 100,
  scale: 500,
  breakout: 2000
};
const dailyMax = tierLimits[status] || tierLimits.seed;

// ---- Compute 7-day aggregates ----
let totalSpend7d = 0;
let totalRevenue7d = 0;
let organicTrafficValues = [];
let totalChurn = 0;
let totalActiveCustomers = 0;
let campaigns = []; // { spend, revenue, startedAt }

for (const day of metricsRaw) {
  totalSpend7d += parseFloat(day.spend) || 0;
  totalRevenue7d += parseFloat(day.revenue) || 0;
  if (day.organic_traffic !== null && day.organic_traffic !== undefined) {
    organicTrafficValues.push({ date: day.date, value: parseFloat(day.organic_traffic) || 0 });
  }
  totalChurn += parseInt(day.churn_count) || 0;
  totalActiveCustomers = Math.max(totalActiveCustomers, parseInt(day.active_customers) || 0);
  if (day.campaign_spend) {
    campaigns.push({
      spend: parseFloat(day.campaign_spend) || 0,
      revenue: parseFloat(day.campaign_revenue) || 0,
      startedAt: day.campaign_started_at
    });
  }
}

// Today's spend from budget entry
const todaySpend = parseFloat(budgetEntry.total_spend) || 0;

// ---- Breaker Checks ----
const breakers = [];

// 1. 7-day spend > 3x trailing revenue => auto-pause
const trailingRevenue = totalRevenue7d;
if (trailingRevenue > 0 && totalSpend7d > 3 * trailingRevenue) {
  breakers.push({
    rule: 'SPEND_3X_REVENUE',
    severity: 'CRITICAL',
    message: `7-day spend ($${totalSpend7d.toFixed(2)}) exceeds 3x trailing 7-day revenue ($${trailingRevenue.toFixed(2)}). Auto-pause triggered.`,
    action: 'pause_all_spend'
  });
} else if (trailingRevenue === 0 && totalSpend7d > dailyMax * 7) {
  // No revenue yet but spending above tier limit over 7 days
  breakers.push({
    rule: 'SPEND_3X_REVENUE',
    severity: 'CRITICAL',
    message: `7-day spend ($${totalSpend7d.toFixed(2)}) with $0 trailing revenue. Auto-pause triggered.`,
    action: 'pause_all_spend'
  });
}

// 2. Campaign ROAS check: positive ROAS within 72 hours or pause
const now = new Date();
for (const c of campaigns) {
  if (c.startedAt) {
    const started = new Date(c.startedAt);
    const hoursSinceStart = (now - started) / (1000 * 60 * 60);
    if (hoursSinceStart >= 72 && c.spend > 0 && c.revenue <= c.spend) {
      breakers.push({
        rule: 'CAMPAIGN_ROAS_NEGATIVE',
        severity: 'HIGH',
        message: `Campaign running ${Math.round(hoursSinceStart)}h with negative ROAS (spend: $${c.spend.toFixed(2)}, revenue: $${c.revenue.toFixed(2)}). Must pause.`,
        action: 'pause_campaign'
      });
    }
  }
}

// 3. Churn > 15% => pause acquisition, redirect to retention
const churnRate = totalActiveCustomers > 0 ? (totalChurn / totalActiveCustomers) * 100 : 0;
if (churnRate > 15) {
  breakers.push({
    rule: 'CHURN_ABOVE_15PCT',
    severity: 'HIGH',
    message: `Churn rate ${churnRate.toFixed(1)}% (${totalChurn} churned / ${totalActiveCustomers} active) exceeds 15%. Pause acquisition, redirect to retention.`,
    action: 'pause_acquisition_redirect_retention'
  });
}

// 4. Organic traffic drops 40%+ in trailing period
// Compare first half vs second half of the 7-day window as proxy
if (organicTrafficValues.length >= 4) {
  const sorted = organicTrafficValues.sort((a, b) => a.date.localeCompare(b.date));
  const mid = Math.floor(sorted.length / 2);
  const firstHalf = sorted.slice(0, mid);
  const secondHalf = sorted.slice(mid);
  const avgFirst = firstHalf.reduce((s, v) => s + v.value, 0) / firstHalf.length;
  const avgSecond = secondHalf.reduce((s, v) => s + v.value, 0) / secondHalf.length;
  if (avgFirst > 0) {
    const dropPct = ((avgFirst - avgSecond) / avgFirst) * 100;
    if (dropPct >= 40) {
      breakers.push({
        rule: 'ORGANIC_TRAFFIC_DROP_40PCT',
        severity: 'HIGH',
        message: `Organic traffic dropped ${dropPct.toFixed(1)}% (avg ${avgFirst.toFixed(0)} -> ${avgSecond.toFixed(0)}). Emergency review required.`,
        action: 'emergency_review'
      });
    }
  }
}

// 5. Daily budget tier limit exceeded
if (todaySpend > dailyMax) {
  breakers.push({
    rule: 'DAILY_TIER_LIMIT_EXCEEDED',
    severity: 'HIGH',
    message: `Today's spend ($${todaySpend.toFixed(2)}) exceeds ${status} tier daily max ($${dailyMax}). Overspend by $${(todaySpend - dailyMax).toFixed(2)}.`,
    action: 'cap_daily_spend'
  });
}

// ---- Build output ----
const triggered = breakers.length > 0;
const reasonSummary = breakers.map(b => `[${b.severity}] ${b.rule}: ${b.message}`).join('\n');

return [{
  json: {
    business_id: businessId,
    business_name: businessName,
    status: status,
    today: today,
    daily_max: dailyMax,
    today_spend: todaySpend,
    spend_7d: totalSpend7d,
    revenue_7d: totalRevenue7d,
    churn_rate: churnRate,
    current_mrr: currentMrr,
    circuit_breaker_triggered: triggered,
    breaker_count: breakers.length,
    breakers: breakers,
    circuit_breaker_reason: reasonSummary || 'All clear - no breakers triggered',
    summary_line: triggered
      ? `${businessName}: ${breakers.length} breaker(s) triggered - ${breakers.map(b => b.rule).join(', ')}`
      : `${businessName}: All clear`
  }
}];

