// Collect summary from the breaker check after alert actions
const staticData = $getWorkflowStaticData('global');
if (!staticData.summaryLines) staticData.summaryLines = [];

const data = $('Check Circuit Breakers').first().json;
staticData.summaryLines.push(data.summary_line);

return [{ json: { done: true, summary_line: data.summary_line } }];

// Build final daily summary report from all collected lines
const staticData = $getWorkflowStaticData('global');
const summaryLines = staticData.summaryLines || ['No businesses processed'];
const today = new Date().toISOString().split('T')[0];

const totalBreakers = summaryLines.filter(l => !l.includes('All clear')).length;
const totalClear = summaryLines.filter(l => l.includes('All clear')).length;

const report = `# Budget Circuit Breaker - Daily Report

**Date:** ${today}
**Run Time:** ${new Date().toISOString()}

## Summary

- **Businesses checked:** ${summaryLines.length}
- **Breakers triggered:** ${totalBreakers}
- **All clear:** ${totalClear}

## Details

${summaryLines.map(l => '- ' + l).join('\n')}

---
*Auto-generated by Budget Circuit Breaker workflow*
`;

// Clear static data for next run
staticData.summaryLines = [];

return [{ json: { report, today, fileName: 'reports/circuit-breaker-' + today + '.md' } }];
